changeSet.sql:
ALTER TABLE public.magic_item     ADD COLUMN IF NOT EXISTS created_by uuid, ADD COLUMN IF NOT EXISTS updated_by uuid;
ALTER TABLE public.equipment_item ADD COLUMN IF NOT EXISTS created_by uuid, ADD COLUMN IF NOT EXISTS updated_by uuid;
ALTER TABLE public.background     ADD COLUMN IF NOT EXISTS created_by uuid, ADD COLUMN IF NOT EXISTS updated_by uuid;

ALTER TABLE public.magic_item     ADD CONSTRAINT fk_magic_item_created_by     FOREIGN KEY (created_by) REFERENCES public.users(id) ON DELETE SET NULL;
ALTER TABLE public.magic_item     ADD CONSTRAINT fk_magic_item_updated_by     FOREIGN KEY (updated_by) REFERENCES public.users(id) ON DELETE SET NULL;
ALTER TABLE public.equipment_item ADD CONSTRAINT fk_equipment_item_created_by FOREIGN KEY (created_by) REFERENCES public.users(id) ON DELETE SET NULL;
ALTER TABLE public.equipment_item ADD CONSTRAINT fk_equipment_item_updated_by FOREIGN KEY (updated_by) REFERENCES public.users(id) ON DELETE SET NULL;
ALTER TABLE public.background     ADD CONSTRAINT fk_background_created_by      FOREIGN KEY (created_by) REFERENCES public.users(id) ON DELETE SET NULL;
ALTER TABLE public.background     ADD CONSTRAINT fk_background_updated_by      FOREIGN KEY (updated_by) REFERENCES public.users(id) ON DELETE SET NULL;

UPDATE public.magic_item     m SET created_by = hp.author_id, updated_by = hp.author_id FROM public.homebrew_packages hp WHERE m.homebrew_id = hp.id AND m.created_by IS NULL;
UPDATE public.equipment_item e SET created_by = hp.author_id, updated_by = hp.author_id FROM public.homebrew_packages hp WHERE e.homebrew_id = hp.id AND e.created_by IS NULL;
UPDATE public.background     b SET created_by = hp.author_id, updated_by = hp.author_id FROM public.homebrew_packages hp WHERE b.homebrew_id = hp.id AND b.created_by IS NULL;

rollback.sql:
ALTER TABLE public.magic_item     DROP CONSTRAINT IF EXISTS fk_magic_item_created_by,     DROP CONSTRAINT IF EXISTS fk_magic_item_updated_by;
ALTER TABLE public.equipment_item DROP CONSTRAINT IF EXISTS fk_equipment_item_created_by, DROP CONSTRAINT IF EXISTS fk_equipment_item_updated_by;
ALTER TABLE public.background     DROP CONSTRAINT IF EXISTS fk_background_created_by,      DROP CONSTRAINT IF EXISTS fk_background_updated_by;
ALTER TABLE public.magic_item     DROP COLUMN IF EXISTS created_by, DROP COLUMN IF EXISTS updated_by;
ALTER TABLE public.equipment_item DROP COLUMN IF EXISTS created_by, DROP COLUMN IF EXISTS updated_by;
ALTER TABLE public.background     DROP COLUMN IF EXISTS created_by, DROP COLUMN IF EXISTS updated_by;
